from pydantic import BaseModel

class ExtractionMetrics:
    def __init__(self):
        self.field_stats = defaultdict(lambda: {'total': 0, 'populated': 0})

    def validate_model(self, model: BaseModel):
        for field_name, field_value in model.model_dump().items():
            self.field_stats[field_name]['total'] += 1
            if field_value is not None:
                self.field_stats[field_name]['populated'] += 1

        # Alert on fields < 80% population rate
        for field, stats in self.field_stats.items():
            rate = stats['populated'] / stats['total']
            if rate < 0.8:
                print(f'⚠️ PARTIAL EXTRACTION: {field} = {rate:.1%}')

