from pydantic import BaseModel, Field, validator
from typing import Literal

class SafeToolCall(BaseModel):
    tool: Literal['search', 'calculator', 'write']

    @validator('tool', pre=True)
    def normalize_tool(cls, v):
        tool_map = {
            'search_web': 'search',
            'google': 'search',
            'calc': 'calculator',
            'math': 'calculator',
            'file': 'write'
        }
        return tool_map.get(v.lower(), v)

client = from_openai(openai_client, response_model=SafeToolCall)

# Now handles hallucinated values gracefully
response = client.chat.completions.create(
    model='gpt-4o-mini',
    response_model=SafeToolCall,
    messages=[{'role': 'user', 'content': 'Use search_web tool'}]
)
